type DashboardState = typeof defaultState;

function mergeState(raw: Partial<DashboardState>): DashboardState {
  return { ...defaultState, ...raw, account: { ...defaultState.account, ...(raw.account || {}) }, pet: { ...defaultState.pet, ...(raw.pet || {}) }, vet: { ...defaultState.vet, ...(raw.vet || {}) }, settings: { ...defaultState.settings, ...(raw.settings || {}) }, subscription: { ...defaultState.subscription, ...(raw.subscription || {}) }, goals: { ...defaultState.goals, ...(raw.goals || {}) }, walks: raw.walks || defaultState.walks, savedRoutes: raw.savedRoutes || defaultState.savedRoutes, meals: raw.meals || defaultState.meals, records: raw.records || defaultState.records, lostReports: raw.lostReports || defaultState.lostReports, packFriends: raw.packFriends || defaultState.packFriends, packGroups: raw.packGroups || defaultState.packGroups, packMessages: raw.packMessages || defaultState.packMessages, training: raw.training || defaultState.training, play: raw.play || defaultState.play, achievements: raw.achievements || defaultState.achievements, managedUsers: raw.managedUsers || defaultState.managedUsers, reminders: raw.reminders || defaultState.reminders };
}

function loadState() {
  if (typeof window === 'undefined') return defaultState;
  try { return mergeState(JSON.parse(localStorage.getItem('mypetid.dashboard') || '{}')); } catch { return defaultState; }
}

function ageFromBirthday(value: string) {
  if (!value) return 'Birthday not set';
  const birth = new Date(`${value}T00:00:00`);
  if (Number.isNaN(birth.getTime())) return 'Birthday not set';
  const now = new Date();
  let years = now.getFullYear() - birth.getFullYear();
  let months = now.getMonth() - birth.getMonth();
  if (now.getDate() < birth.getDate()) months -= 1;
  if (months < 0) { years -= 1; months += 12; }
  return years > 0 ? `${years} yr ${months} mo` : `${Math.max(0, months)} mo`;
}

function formatCoords(coords?: Coords) {
  if (!coords) return 'Waiting for device GPS';
  return `${coords.label}: ${coords.lat.toFixed(5)}, ${coords.lng.toFixed(5)}${coords.accuracy ? ` ±${Math.round(coords.accuracy)}m` : ''}`;
}

function walkMapUrl(start?: Coords, end?: Coords) {
  const fallback = 'https://maps.google.com/maps?q=44.097371370963934,-70.16535158888728&z=14&output=embed';
  if (start && end) return `https://maps.google.com/maps?saddr=${start.lat},${start.lng}&daddr=${end.lat},${end.lng}&z=15&output=embed`;
  const point = start || end;
  return point ? `https://maps.google.com/maps?q=${point.lat},${point.lng}&z=15&output=embed` : fallback;
}

function Field({ label, value, onChange, type = 'text', hint, min }: { label: string; value: string; type?: string; hint?: string; min?: string; onChange: (value: string) => void }) {
  return <label>{label}<input min={min} type={type} value={value} onChange={(event) => onChange(event.target.value)} />{hint && <small>{hint}</small>}</label>;
}
function SelectField({ label, value, options, onChange }: { label: string; value: string; options: string[]; onChange: (value: string) => void }) {
  return <label>{label}<select value={value} onChange={(event) => onChange(event.target.value)}>{options.map((option) => <option key={option} value={option}>{option}</option>)}</select></label>;
}
function TextArea({ label, value, onChange }: { label: string; value: string; onChange: (value: string) => void }) {
  return <label>{label}<textarea value={value} onChange={(event) => onChange(event.target.value)} /></label>;
}
function ImageUpload({ label, onLoaded }: { label: string; onLoaded: (dataUrl: string) => void }) {
  return <label>{label}<input type="file" accept="image/*" onChange={(event) => { const file = event.target.files?.[0]; if (!file) return; const reader = new FileReader(); reader.onload = () => onLoaded(String(reader.result || '')); reader.readAsDataURL(file); }} /><small>Previewed in this browser now; production should store private files in Supabase Storage with owner/admin RLS.</small></label>;
}
function milesBetween(start?: Coords, end?: Coords) { if (!start || !end) return 0; const toRad = (value: number) => value * Math.PI / 180; const r = 3958.8; const dLat = toRad(end.lat - start.lat); const dLng = toRad(end.lng - start.lng); const a = Math.sin(dLat / 2) ** 2 + Math.cos(toRad(start.lat)) * Math.cos(toRad(end.lat)) * Math.sin(dLng / 2) ** 2; return Number((2 * r * Math.asin(Math.sqrt(a))).toFixed(3)); }
function coordsFromPosition(position: GeolocationPosition, label: string): Coords { return { lat: position.coords.latitude, lng: position.coords.longitude, accuracy: position.coords.accuracy, timestamp: position.timestamp, label }; }
function canUseDirectDistance(start?: Coords, end?: Coords) { return Boolean(start && end && (start.accuracy || 999) <= 50 && (end.accuracy || 999) <= 50 && milesBetween(start, end) >= 0.02); }
function statusBadge(status: string) { if (status.includes('Service')) return '🦮'; if (status.includes('Therapy')) return '💙'; if (status.includes('Emotional')) return '💚'; if (status.includes('Working')) return '⭐'; return ''; }
function rescueBadge(status: string) { return status && status !== 'Not set' ? '🏠' : ''; }

